INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00929', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '某私校面臨招生困難，據傳將於近年停辦轉型為社會福利機構。謝老師已在此校任教25年，想辦理自願 退休，應依下列何者辦理？', '["教師法", "私立學校法施行細則", "學校法人及其所屬私立學校教職員退休撫卹離職資遣條例", "大專校院轉型及退場基金收支保管及運用辦法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00930', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '為維護我國教育健全發展之需要，提升教育經費運用績效，下列何項不是教育經費編列與管理法所規定？', '["各級政府教育經費預算合計應不低於該年度預算籌編時之前3年度決算歲入淨額平均值之百分之二十三", "各級主管教育行政機關對公、私立學校及其他教育機構應依法進行財務監督", "為兼顧各地區教育之均衡發展，各級政府對於偏遠及特殊地區教育經費之補助，應依據國民教育法之 規定優先編列", "直轄市、縣（市）政府於前一年度違反第3條或第8條規定時，應於當年度教育經費計算中，增加其 應分擔數額或扣減其一般教育補助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00931', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '下列有關高級中等學校課程的辦理情形，何者符合規定？', '["選修課程每班人數得超過原核定之班級人數，但不得低於12人。情形特殊或學校經費足以支應者，得 降低至10人", "與大專校院合作開課之選修課程，學生每學期至多得選修4學分", "普通型學校、綜合型學校及單科型學校，學生於修業年限內，其自主學習合計應至少18小時", "充實（增廣）教學或補強型教學採全學期授課者，一年級每週至多1節、二年級每週至多2節、三年 級每週至多3節"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00932', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依校園霸凌防制準則規定，學校調查處理校園霸凌事件時，應依下列何種方式辦理？', '["調查時，應給予雙方當事人陳述意見之機會；不得由法定代理人陪同", "調查時，應給予行為人與被霸凌人對質之機會", "協助調查人之姓名不需要保密", "申請人撤回申請調查時，主管機關認為情節重大者，應命學校繼續調查處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00933', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '對於國民小學及國民中學之教科圖書，下列那項不是國民教育法的規定？', '["國民小學及國民中學之教科圖書，由學校課程發展委員會訂定辦法公開選用之", "國民小學及國民中學之教科圖書，由教育部審定，必要時得編定之", "國民小學及國民中學藝能及活動科目之教科圖書，應免費借用予需要的學生", "教科圖書審定委員會由學科及課程專家、教師及教育行政機關代表等組成，教師代表不得少於三分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00934', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依國民教育法，國民小學及國民中學之課程，應以國民生活教育及下列何者為中心？', '["身心健全發展", "解決問題能力", "民族精神教育", "世界公民責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00935', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關公立各級學校校長相關資格，應依下列那項法律為主？', '["教師法", "國民教育法", "教育人員任用條例", "教師待遇條例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00936', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據教師法，有關高級中等以下學校教師之聘任，下列何者錯誤？', '["教師評審委員會之組成，應包括教師代表、學校行政人員代表及家長會長", "依國民教育法或高級中等教育法回任教師之校長，不需經教師評審委員會審查", "高級中等以下學校教師之聘任，以具有教師證書者為限", "教師的長期聘任需經教師評審委員會全體委員三分之二以上審查通過"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00937', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '教師因學校或主管機關對其依法申請之案件，於法定期間內應作為而不作為，認為損害其權益者得提起 申訴，下列何者正確？', '["申訴之提起，應於收受或知悉措施之次日起20日內以書面為之", "再申訴應於申訴評議書達到之次日起10日內以書面為之", "申訴須以書面為之", "法令未規定應作為之期間者，其期間自學校或主管機關受理申請之日起為3個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00938', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '在身心障礙及資賦優異學生鑑定辦法中，下列那一項不是做為判斷第20條所稱其他特殊才能資賦優異的 依據？', '["在肢體動作、工具運用、資訊、棋藝、牌藝等能力具有卓越潛能或傑出表現者", "參加政府機關或學術研究機構舉辦之國際性或全國性技藝競賽表現特別優異，獲前三等獎項", "經專家學者、指導教師或家長觀察推薦，並檢附專長才能特質與表現卓越或傑出等之具體資料", "在某領域學術性向得分在平均數正2個標準差以上，及檢附專長學科學習表現之具體資料"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
